message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the exciton Rydberg energy (Ry*) and then finding the energy level for the n=3 state. The energy of the exciton state is typically expressed as E_n = E_g - Ry*/n^2. I need to find Ry* first using the 1s peak information.",
  "helpers": [
    {
      "label": "calculate_rydberg_constant",
      "instructions": "Given a band gap of 3 eV and a 1s exciton peak at 1 eV, calculate the effective Rydberg energy (Ry*). Note that the 1s exciton energy is E_g - Ry*. Provide the value of Ry* in eV."
    },
    {
      "label": "calculate_n3_energy_level",
      "instructions": "Given the effective Rydberg energy (Ry*) calculated by the previous helper, calculate the energy of the n = 3 exciton state. The formula is E_n = E_g - (Ry* / n^2), where E_g is the band gap of 3 eV. Provide the final numerical value in eV."
    }
  ],
  "synthesis_brief": "Use the Ry* value from the first helper to calculate the energy of the n=3 state using the formula E_n = E_g - Ry*/n^2. Ensure the final answer is the energy level of the n=3 state relative to the vacuum/ground state as implied by the context of the exciton peak."
}

